firmware_template.source:
#include "vl53l0x.h"
#include <Wire.h>
static Adafruit_VL53L0X lox;
static uint16_t _mm = 0;
static bool _valid = false;
static unsigned long _last = 0;
void vl53l0x_setup() {
  Wire.begin();
  if (!lox.begin()) { Serial.println("[vl53l0x] Init failed!"); return; }
  Serial.println("[vl53l0x] OK");
}
void vl53l0x_loop() {
  if (millis()-_last < 100) return;
  _last = millis();
  VL53L0X_RangingMeasurementData_t m;
  lox.rangingTest(&m, false);
  if (m.RangeStatus != 4) { _mm = m.RangeMilliMeter; _valid = true; }
  else { _valid = false; }
}
uint16_t vl53l0x_get_distance_mm() { return _mm; }
bool vl53l0x_in_range() { return _valid; }
